lucas-theorem.code:
function lucas_theorem(n, k, p) {
    function smallComb(nn, kk) {
        if (kk>nn || kk<0) return 0;
        let num=1, den=1;
        for (let i=0;i<kk;i++) { num=(num*((nn-i)%p))%p; den=(den*(i+1))%p; }
        let denInv=1, base=den%p, e=p-2;
        while (e>0) { if (e&1) denInv=(denInv*base)%p; base=(base*base)%p; e>>=1; }
        return (num*denInv)%p;
    }
    let result=1, nn=n, kk=k;
    while (nn>0 || kk>0) {
        const ni=nn%p, ki=kk%p;
        if (ki>ni) return 0;
        result=(result*smallComb(ni,ki))%p;
        nn=Math.floor(nn/p); kk=Math.floor(kk/p);
    }
    return result;
}

