    const need={}; for (const ch of t) need[ch]=(need[ch]||0)+1;
    let required=Object.keys(need).length, formed=0;
    const window={};
    let left=0, best=Infinity;
    for (let right=0;right<s.length;right++) {
        const ch=s[right]; window[ch]=(window[ch]||0)+1;
        if (need[ch]!==undefined && window[ch]===need[ch]) formed++;
        while (formed===required) {
            best=Math.min(best, right-left+1);
            const lc=s[left]; window[lc]--;
            if (need[lc]!==undefined && window[lc]<need[lc]) formed--;
            left++;
        }
    }
    const r = best===Infinity?0:best;
    return r===0?r:r;
}

