    let count = 0;
    function bfs(sr, sc) {
        const q = [[sr,sc]]; visited[sr][sc] = true; let qi = 0;
        while (qi < q.length) {
            const [r,c] = q[qi]; qi++;
            for (const [dr,dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
                const nr=r+dr, nc=c+dc;
                if (nr>=0&&nr<m&&nc>=0&&nc<n&&!visited[nr][nc]&&grid[nr][nc]===1) { visited[nr][nc]=true; q.push([nr,nc]); }
            }
        }
    }
    for (let i=0;i<m;i++) for (let j=0;j<n;j++) { if (grid[i][j]===1 && !visited[i][j]) { count++; bfs(i,j); } }
    return count;
}

