    const offset=total; const size=2*total+1;
    let dp=new Array(size).fill(0); dp[offset]=1;
    for (const x of nums) {
        const ndp=new Array(size).fill(0);
        for (let s=0;s<size;s++) {
            if (dp[s]===0) continue;
            if (s+x<size) ndp[s+x]+=dp[s];
            if (s-x>=0) ndp[s-x]+=dp[s];
