function word_wrap(lengths, width) {
    const n=lengths.length; const INF=1e15;
    const dp=new Array(n+1).fill(INF); dp[n]=0;
    for (let i=n-1;i>=0;i--) {
        let lineLen=-1;
        for (let j=i;j<n;j++) {
            lineLen += lengths[j]+1;
            if (lineLen>width) break;
            const cost = (j===n-1) ? 0 : (width-lineLen)*(width-lineLen)*(width-lineLen);
            if (dp[j+1]+cost<dp[i]) dp[i]=dp[j+1]+cost;
        }
    }
    return dp[0];
}
